class Solution:
    def smallestValue(self, n: int) -> int:
        def prime_factors(n):
            i = 2
            factors = []
            while i * i <= n:
                if n % i:
                    i += 1
                else:
                    n //= i
                    factors.append(i)
            if n > 1:
                factors.append(n)
            return factors

        while True:
            factors = prime_factors(n)
            n = sum(factors)
            if n == 3:
                return n
